import json

# Load OrderItems
orderitems_raw = locals()['var_functions.query_db:11']
if isinstance(orderitems_raw, str) and orderitems_raw.endswith('.json'):
    with open(orderitems_raw, 'r') as f:
        orderitems = json.load(f)
else:
    orderitems = orderitems_raw

# Load recent Cases
cases_raw = locals()['var_functions.query_db:12']
if isinstance(cases_raw, str) and cases_raw.endswith('.json'):
    with open(cases_raw, 'r') as f:
        cases = json.load(f)
else:
    cases = cases_raw

# Clean OrderItem IDs (remove leading # and trailing spaces)
orderitem_ids_clean = set()
for item in orderitems:
    orderitem_id = item['Id']
    if orderitem_id.startswith('#'):
        orderitem_id = orderitem_id[1:]
    orderitem_id = orderitem_id.strip()
    orderitem_ids_clean.add(orderitem_id)

# Debug: print some values
print('Sample OrderItem IDs:', list(orderitem_ids_clean)[:5])
print('Total OrderItem IDs:', len(orderitem_ids_clean))

# Find cases for these order items
ai_cirku_cases = []
for case in cases:
    case_orderitem_id = case.get('orderitemid__c', '')
    if case_orderitem_id:
        if case_orderitem_id.startswith('#'):
            case_orderitem_id = case_orderitem_id[1:]
        case_orderitem_id = case_orderitem_id.strip()

        if case_orderitem_id in orderitem_ids_clean:
            ai_cirku_cases.append(case)

# Count issues
issue_counts = {}
for case in ai_cirku_cases:
    issue_id = case.get('issueid__c', '')
    if issue_id:
        issue_counts[issue_id] = issue_counts.get(issue_id, 0) + 1

result = {
    'total_ai_cirku_cases': len(ai_cirku_cases),
    'issue_counts': issue_counts,
    'most_frequent_issue': max(issue_counts, key=issue_counts.get) if issue_counts else None
}

print('__RESULT__:')
print(json.dumps(result))

